import{_ as r,o as e,c as d,a4 as a}from"./chunks/framework.DiadTcoQ.js";const m=JSON.parse('{"title":"Le futur","description":"","frontmatter":{},"headers":[],"relativePath":"module-4/future.md","filePath":"module-4/future.md"}'),i={name:"module-4/future.md"};function n(s,t,o,u,l,h){return e(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="le-futur" tabindex="-1">Le futur <a class="header-anchor" href="#le-futur" aria-label="Permalink to “Le futur”">​</a></h1><p>L&#39;espagnol dispose de deux façons d&#39;exprimer le futur, selon le registre et le degré de certitude.</p><h2 id="futur-proche-ir-a-infinitif" tabindex="-1">Futur proche : ir + a + infinitif <a class="header-anchor" href="#futur-proche-ir-a-infinitif" aria-label="Permalink to “Futur proche : ir + a + infinitif”">​</a></h2><p>La forme la plus courante à l&#39;oral. Elle correspond au futur proche français (aller + infinitif).</p><blockquote><p><em>Voy a comer.</em> — Je vais manger. <em>¿Qué vas a hacer mañana?</em> — Qu&#39;est-ce que tu vas faire demain ? <em>Va a llover.</em> — Il va pleuvoir.</p></blockquote><p>La construction est invariable : conjuguer <strong>ir</strong> au présent + <strong>a</strong> + infinitif.</p><h2 id="futur-simple" tabindex="-1">Futur simple <a class="header-anchor" href="#futur-simple" aria-label="Permalink to “Futur simple”">​</a></h2><p>Formé directement sur l&#39;infinitif, sans auxiliaire. Terminaisons identiques pour les trois groupes.</p><h3 id="verbes-reguliers" tabindex="-1">Verbes réguliers <a class="header-anchor" href="#verbes-reguliers" aria-label="Permalink to “Verbes réguliers”">​</a></h3><table tabindex="0"><thead><tr><th>Pronom</th><th>Terminaison</th><th>hablar</th><th>comer</th><th>vivir</th></tr></thead><tbody><tr><td>yo</td><td>-é</td><td>hablaré</td><td>comeré</td><td>viviré</td></tr><tr><td>tú</td><td>-ás</td><td>hablarás</td><td>comerás</td><td>vivirás</td></tr><tr><td>él / ella / usted</td><td>-á</td><td>hablará</td><td>comerá</td><td>vivirá</td></tr><tr><td>nosotros</td><td>-emos</td><td>hablaremos</td><td>comeremos</td><td>viviremos</td></tr><tr><td>vosotros</td><td>-éis</td><td>hablaréis</td><td>comeréis</td><td>viviréis</td></tr><tr><td>ellos / ustedes</td><td>-án</td><td>hablarán</td><td>comerán</td><td>vivirán</td></tr></tbody></table><h3 id="verbes-irreguliers" tabindex="-1">Verbes irréguliers <a class="header-anchor" href="#verbes-irreguliers" aria-label="Permalink to “Verbes irréguliers”">​</a></h3><p>La base change mais les terminaisons restent identiques.</p><table tabindex="0"><thead><tr><th>Infinitif</th><th>Base irrégulière</th><th>yo</th><th>ellos</th></tr></thead><tbody><tr><td>tener</td><td>tendr-</td><td>tendré</td><td>tendrán</td></tr><tr><td>poder</td><td>podr-</td><td>podré</td><td>podrán</td></tr><tr><td>querer</td><td>querr-</td><td>querré</td><td>querrán</td></tr><tr><td>saber</td><td>sabr-</td><td>sabré</td><td>sabrán</td></tr><tr><td>venir</td><td>vendr-</td><td>vendré</td><td>vendrán</td></tr><tr><td>hacer</td><td>har-</td><td>haré</td><td>harán</td></tr><tr><td>decir</td><td>dir-</td><td>diré</td><td>dirán</td></tr><tr><td>salir</td><td>saldr-</td><td>saldré</td><td>saldrán</td></tr><tr><td>poner</td><td>pondr-</td><td>pondré</td><td>pondrán</td></tr></tbody></table><h2 id="futur-proche-vs-futur-simple" tabindex="-1">Futur proche vs futur simple <a class="header-anchor" href="#futur-proche-vs-futur-simple" aria-label="Permalink to “Futur proche vs futur simple”">​</a></h2><table tabindex="0"><thead><tr><th>ir + a + infinitif</th><th>Futur simple</th></tr></thead><tbody><tr><td>Intention, plan concret</td><td>Prédiction, hypothèse</td></tr><tr><td>Futur immédiat ou certain</td><td>Futur lointain ou incertain</td></tr><tr><td><em>Voy a llamarte esta tarde.</em></td><td><em>Algún día hablaré español perfectamente.</em></td></tr></tbody></table><p>Le futur simple peut aussi exprimer une supposition au présent :</p><blockquote><p><em>¿Dónde estará Juan?</em> — Où peut bien être Juan ? <em>Tendrá unos cuarenta años.</em> — Il doit avoir dans les quarante ans.</p></blockquote><p><strong>Marqueurs temporels typiques :</strong> mañana · pasado mañana · el próximo lunes · el año que viene · dentro de + durée · algún día · pronto</p>',18)])])}const c=r(i,[["render",n]]);export{m as __pageData,c as default};
